import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine().trim(); // Read a line of input and remove leading/trailing spaces

        // Validate input length
        if (input.length() > 10) {
            System.out.println("Input exceeds maximum buffer size.");
            return;
        }

        // Copy input into a buffer with correct length
        byte[] buffer = new byte[10];
        System.arraycopy(input.getBytes(), 0, buffer, 0, input.length());

        // Print the content of the buffer
        System.out.println("Buffer content: " + new String(buffer));
    }
}

